    #[doc = "    height. If only a single dimension is given (e.g. only width), the"]
    #[doc = "    image will be shrunk or enlarged to exactly match that dimension."]
    #[doc = "    Aspect ratio is always preserved."]
    #[doc = "  - cover: Resizes (shrinks or enlarges) to fill the entire area of width"]
    #[doc = "    and height. If the image has an aspect ratio different from the ratio"]
    #[doc = "    of width and height, it will be cropped to fit."]
    #[doc = "  - crop: The image will be shrunk and cropped to fit within the area"]
    #[doc = "    specified by width and height. The image will not be enlarged. For images"]
    #[doc = "    smaller than the given dimensions it's the same as scale-down. For"]
    #[doc = "    images larger than the given dimensions, it's the same as cover."]
    #[doc = "    See also trim."]
    #[doc = "  - pad: Resizes to the maximum size that fits within the given width and"]
